import React, { useState } from 'react';

const PRESETS = ['#2563eb', '#16a34a', '#d97706', '#dc2626', '#7c3aed', '#0891b2', '#111827', '#f59e0b'];

const toHex = ({ r, g, b }) =>
  '#' + [r, g, b].map((c) => c.toString(16).padStart(2, '0')).join('');

const fromHex = (h) => ({
  r: parseInt(h.slice(1, 3), 16),
  g: parseInt(h.slice(3, 5), 16),
  b: parseInt(h.slice(5, 7), 16),
});

const luminance = ({ r, g, b }) => (0.299 * r + 0.587 * g + 0.114 * b) / 255;

export default function ColorPicker() {
  const [rgb, setRgb] = useState({ r: 37, g: 99, b: 235 });
  const hex = toHex(rgb);
  const textColor = luminance(rgb) > 0.55 ? '#111' : '#fff';

  const channel = (key, color) => (
    <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
      <span style={{ width: 14, color }}>{key.toUpperCase()}</span>
      <input
        type="range"
        min="0"
        max="255"
        value={rgb[key]}
        onChange={(e) => setRgb((c) => ({ ...c, [key]: Number(e.target.value) }))}
        style={{ flex: 1 }}
      />
      <span style={{ width: 32, textAlign: 'right' }}>{rgb[key]}</span>
    </label>
  );

  return (
    <div style={{ maxWidth: 320 }}>
      <div style={{ height: 96, borderRadius: 10, background: hex, color: textColor, display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'monospace', fontSize: 20 }}>
        {hex}
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 12 }}>
        {channel('r', '#dc2626')}
        {channel('g', '#16a34a')}
        {channel('b', '#2563eb')}
      </div>

      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginTop: 12 }}>
        {PRESETS.map((p) => (
          <button
            key={p}
            onClick={() => setRgb(fromHex(p))}
            aria-label={p}
            style={{ width: 28, height: 28, borderRadius: 6, border: hex === p ? '2px solid #111' : '1px solid #ddd', background: p, cursor: 'pointer' }}
          />
        ))}
      </div>
    </div>
  );
}

