import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-color-picker',
  template: `
    <div style="max-width: 320px;">
      <div
        style="height: 96px; border-radius: 10px; display: flex; align-items: center; justify-content: center; font-family: monospace; font-size: 20px;"
        [style.background]="hex"
        [style.color]="textColor"
      >{{ hex }}</div>

      <div style="display: flex; flex-direction: column; gap: 8px; margin-top: 12px;">
        <label *ngFor="let ch of channels" style="display: flex; align-items: center; gap: 8px;">
          <span style="width: 14px;" [style.color]="ch.color">{{ ch.key.toUpperCase() }}</span>
          <input type="range" min="0" max="255" [value]="rgb[ch.key]" (input)="rgb[ch.key] = toNum($any($event.target).value)" style="flex: 1;" />
          <span style="width: 32px; text-align: right;">{{ rgb[ch.key] }}</span>
        </label>
      </div>

      <div style="display: flex; flex-wrap: wrap; gap: 8px; margin-top: 12px;">
        <button
          *ngFor="let p of presets"
          (click)="applyPreset(p)"
          [attr.aria-label]="p"
          [style.background]="p"
          [style.border]="hex === p ? '2px solid #111' : '1px solid #ddd'"
          style="width: 28px; height: 28px; border-radius: 6px; cursor: pointer;"
        ></button>
      </div>
    </div>
  `,
})
export class ColorPickerComponent {
  rgb: Record<string, number> = { r: 37, g: 99, b: 235 };
  channels = [
    { key: 'r', color: '#dc2626' },
    { key: 'g', color: '#16a34a' },
    { key: 'b', color: '#2563eb' },
  ];
  presets = ['#2563eb', '#16a34a', '#d97706', '#dc2626', '#7c3aed', '#0891b2', '#111827', '#f59e0b'];

  toNum(v: string): number {
    return Number(v);
  }

  get hex(): string {
    return '#' + ['r', 'g', 'b'].map((k) => this.rgb[k].toString(16).padStart(2, '0')).join('');
  }

  get textColor(): string {
    const l = (0.299 * this.rgb['r'] + 0.587 * this.rgb['g'] + 0.114 * this.rgb['b']) / 255;
    return l > 0.55 ? '#111' : '#fff';
  }

  applyPreset(h: string): void {
    this.rgb['r'] = parseInt(h.slice(1, 3), 16);
    this.rgb['g'] = parseInt(h.slice(3, 5), 16);
    this.rgb['b'] = parseInt(h.slice(5, 7), 16);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Color Picker Demo</h1>
      <app-color-picker></app-color-picker>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, ColorPickerComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
